import style from "./index.module.scss"
import template from './index.html'

let checkboxDescriptionId = 0
export default class Checkbox extends HTMLElement {
  // set type(value: string) {
  //   this.setAttribute("type", value)
  // }
  // get type(): string {
  //   return this.getAttribute("type") || ""
  // }
  // set active(value: string) {
  //   this.setAttribute("active", value)
  // }
  // get active(): boolean {
  //   const value = this.getAttribute("active")
  //   return value === "true" ? true : false
  // }
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return ["type"];
  }
  attributeChangedCallback(name, oldValue, newValue) {
  }

  willLoad = () => {
    this.checkboxEle = this.shadowRoot?.querySelector("input")
    this.descriptionEle = this.shadowRoot?.querySelector(".description")
    const id = ++checkboxDescriptionId
    this.descriptionEle.setAttribute("id", id)
    this.checkboxEle.setAttribute("aria-labelledby", id)
  }
  connectedCallback() {
    this.classList.add("hydrated")
    this.willLoad()
    this.render()
  }
  disconnectedCallback() {
  }

  render = () => {
  }
}
